#include <limits.h>

int main() {
    int n;
    scanf("%d", &n);
    int c[n], t[n];

    for (int i = 0; i < n; i++) {
        scanf("%d", &c[i]);
    }

    for (int i = 0; i < n; i++) {
        scanf("%d", &t[i]);
    }

    int at = 100000;
    int tr = 100000;
    int attr = 100000;

    for (int i = 0; i < n; i++) {
        if (t[i] == 1) {
            tr = (c[i] < tr) ? c[i] : tr;
        } else if (t[i] == 2) {
            at = (c[i] < at) ? c[i] : at;
        } else if (t[i] == 3) {
            attr = (c[i] < attr) ? c[i] : attr;
        }
    }

    int minTotalCost = (tr + at < attr) ? (tr + at) : attr;

    if (minTotalCost == INT_MAX) {
        printf("-1\n");
    } else {
        printf("%d\n", minTotalCost);
    }

    return 0;
}

